#include <fstream>
#include <iostream>
#include <string>
using namespace std;

int main() {
 // Writing to file
 ofstream outFile("student.txt");
 if (!outFile.is_open()) {
 cout << "Error opening file for writing";
 return 1;
 }

 string name = "John";
 int age = 20;
 float marks = 85.5;

 outFile << name << endl;
 outFile << age << endl;
 outFile << marks << endl;
 outFile.close();

 // Reading from file
 ifstream inFile("student.txt");
 if (!inFile.is_open()) {
 cout << "Error opening file for reading";
 return 1;
 }

 getline(inFile, name);
 inFile >> age >> marks;

 cout << "Name: " << name << endl;
 cout << "Age: " << age << endl;
 cout << "Marks: " << marks << endl;

 inFile.close();
 return 0;
}

#include <fstream>
#include <iostream>
using namespace std;

struct Student {
 char name[30];
 int rollno;
 float marks;
};

int main() {
 // Create and write initial records
 ofstream outFile("data.dat", ios::binary);
 Student s1 = {"Alice", 1, 90.5};
 Student s2 = {"Bob", 2, 85.0};
 Student s3 = {"Charlie", 3, 78.5};

 outFile.write((char*)&s1, sizeof(Student));
 outFile.write((char*)&s2, sizeof(Student));
 outFile.write((char*)&s3, sizeof(Student));
 outFile.close();

 // Read and display using random access
 ifstream inFile("data.dat", ios::binary);
 Student s;
 streampos pos;

 // Read second record directly
 inFile.seekg(sizeof(Student), ios::beg); // Move to 2nd record
 inFile.read((char*)&s, sizeof(Student));
 cout << "Second student: " << s.name << ", " << s.marks << endl;

 // Get current position
 pos = inFile.tellg();
 cout << "Current position: " << pos << endl;

 // Read first record
 inFile.seekg(0, ios::beg);
 inFile.read((char*)&s, sizeof(Student));
 cout << "First student: " << s.name << endl;

 inFile.close();
 return 0;
}

#include <fstream>
#include <iostream>
#include <string>
using namespace std;

struct Employee {
 int id;
 char name[30];
 float salary;
};

void updateSalary(const char* filename, int empId, float newSalary) {
 fstream file(filename, ios::in | ios::out | ios::binary);
 if (!file) {
 cout << "Error opening file!";
 return;
 }

 Employee emp;
 bool found = false;

 while (file.read((char*)&emp, sizeof(Employee))) {
 if (emp.id == empId) {
 // Save current position
 streampos pos = file.tellg();

 // Move back one record
 file.seekp(-sizeof(Employee), ios::cur);

 emp.salary = newSalary;
 file.write((char*)&emp, sizeof(Employee));

 found = true;
 cout << "Salary updated for " << emp.name << endl;
 break;
 }
 }

 if (!found) {
 cout << "Employee not found!";
 }

 file.close();
}

#include <fstream>
#include <iostream>
using namespace std;

int main() {
 // Create initial file with some data
 ofstream outFile("log.txt");
 outFile << "Log entry 1: Program started" << endl;
 outFile.close();

 // Append more data using ios::app
 ofstream appendFile("log.txt", ios::app);
 if (appendFile.is_open()) {
 appendFile << "Log entry 2: User logged in" << endl;
 appendFile << "Log entry 3: File opened" << endl;
 appendFile.close();
 }

 // Read and display all content
 ifstream readFile("log.txt");
 string line;
 cout << "Log file contents:" << endl;
 while (getline(readFile, line)) {
 cout << line << endl;
 }
 readFile.close();

 return 0;
}

#include <fstream>
#include <iostream>
using namespace std;

int main() {
 // Attempt to open file for reading
 ifstream inFile("nonexistent.txt");

 // Method 1: Using is_open()
 if (!inFile.is_open()) {
 cout << "Method 1: File not found!" << endl;
 }

 // Method 2: Using boolean conversion
 ifstream inFile2("data.txt", ios::in);
 if (!inFile2) {
 cout << "Method 2: Cannot open file" << endl;
 }

 // Reading with error checking
 ifstream inFile3("sample.txt");
 int num;
 while (inFile3 >> num) {
 cout << num << " ";
 }

 // Check why loop ended
 if (inFile3.eof()) {
 cout << "\nEnd of file reached" << endl;
 } else if (inFile3.fail()) {
 cout << "\nRead operation failed" << endl;
 }

 inFile3.close();
 return 0;
}
